import{_ as t,o as a,c as f,ae as s}from"./chunks/framework.DhtYoOpx.js";const _=JSON.parse('{"title":"useLayoutEffect 和 useEffect 的不同","description":"","frontmatter":{"title":"useLayoutEffect 和 useEffect 的不同","date":"2024-01-01T00:00:00.000Z"},"headers":[],"relativePath":"articles/vue/react/react-uselayouteffect.md","filePath":"articles/vue/react/react-uselayouteffect.md","lastUpdated":1776146674000}'),l={name:"articles/vue/react/react-uselayouteffect.md"};function r(c,e,u,o,i,n){return a(),f("div",null,[...e[0]||(e[0]=[s('<p><strong>1.执行时机不同</strong></p><ul><li>useLayoutEffect先于useEffect执行</li><li>useLayoutEffect先于浏览绘制同步执行</li><li>useEffect后于浏览器绘制异步执行</li></ul><p><strong>2.从性能角度看</strong></p><ul><li>useLayoutEffect是同步执行,如果有繁重的计算逻辑在其中会阻塞浏览器将dom的变更渲染到屏幕上,影响体验</li><li>useEffect是异步执行,不存在上述问题,是大部分场景下需要的使用的api</li></ul><p><strong>3.从使用场景上看</strong></p><ul><li>useLayoutEffect适合处理复杂的用户动画</li><li>使用useEffect可能会产生屏幕闪烁的问题</li></ul><p><strong>参考文档</strong></p><ul><li><a href="https://blog.logrocket.com/useeffect-vs-uselayouteffect-examples/" target="_blank" rel="noreferrer">React useLayoutEffect vs. useEffect with examples</a></li><li><a href="https://www.cnblogs.com/flamestudio/p/13927413.html" target="_blank" rel="noreferrer">React中useLayoutEffect和useEffect的区别</a></li><li><a href="https://www.jianshu.com/p/412c874c5add" target="_blank" rel="noreferrer">useEffect和useLayoutEffect的区别</a></li></ul>',8)])])}const E=t(l,[["render",r]]);export{_ as __pageData,E as default};
